frappe.ui.form.on('Employee Onboarding', {
    company: function(frm) {
        if (!frm.doc.company) {
            frm.set_value('custom_last_employee_id', '');
            frm.set_value('custom_employee_id_', '');
            return;
        }

        frappe.call({
            method: 'hrms_custom.api.get_last_employee_id',
            args: {
                company: frm.doc.company
            },
            callback: function(r) {
                if (r.message) {
                    let last_id = r.message.last_id || 'No employees yet';
                    let next_id = r.message.next_id || '';

                    // Show last ID
                    frm.set_value('custom_last_employee_id', last_id);

                    // Auto fill next ID
                    if (next_id) {
                        frm.set_value('custom_employee_id_', next_id);
                        frappe.show_alert({
                            message: `Last ID: ${last_id} → Next ID: ${next_id}`,
                            indicator: 'green'
                        }, 5);
                    }
                }
            }
        });
    },

    // Also trigger on form load if company already set
    onload: function(frm) {
        if (frm.doc.company && !frm.doc.custom_employee_id_) {
            frm.trigger('company');
        }
    }
});

frappe.ui.form.on("Employee", {
    job_applicant: function(frm) {
        if (!frm.doc.job_applicant) return;

        let field_mapping = {
            "applicant_name": "employee_name",
            "phone_number": "cell_number",
            "custom_personal_email": "personal_email",
            "custom_date_of_birth": "date_of_birth",
            "custom_father_spouse_name": "custom_father_name",
            "custom_permanent_address": "permanent_address",
            "custom_current_address": "current_address",
            "custom_aadhar_number": "custom_aadhaar_number",
            "custom_pan_number": "pan_number",
            "custom_bank_account_number": "bank_ac_no",
            "custom_bank_name": "bank_name",
            "custom_bank_account_holder_name": "custom_name_as_per_bank",
            "custom_ifsc_code": "ifsc_code",
            "custom_uan_number": "custom_uan",
            "custom_spouse_name": "custom_spouse_name",
            "custom_blood_group": "blood_group",
            "custom_religion": "custom_religion",
            "designation": "designation",
            "custom_emergency_contact_name": "person_to_be_contacted",
            "custom_emergency_contact_number": "emergency_phone_number"
        };

        // Value translation for mismatched Select options
        let value_mapping = {
            "marital_status": {
                "Unmarried": "Single",
                "Single": "Single",
                "Married": "Married",
                "Divorced": "Divorced",
                "Widowed": "Widowed"
            }
        };

        let attachment_mapping = [
            { src: "custom_aadhar_upload", doc_type: "Aadhar", card_field: "custom_aadhar_number" },
            { src: "custom_pan_upload", doc_type: "PAN Card", card_field: "custom_pan_number" },
            { src: "custom_bank_passbook", doc_type: "Bank Passbook / Cancelled Cheque", card_field: "custom_bank_account_number" },
            { src: "custom_passport_photo", doc_type: "Passport Photo", card_field: null },
            { src: "custom_10th_marksheet", doc_type: "10th Marksheet", card_field: null },
            { src: "custom_12th_marksheet", doc_type: "12th Marksheet", card_field: null },
            { src: "custom_ug_certificate", doc_type: "Degree Certificate", card_field: null },
            { src: "custom_pg_certificate", doc_type: "PG Degree Certificate", card_field: null },
            { src: "custom_experience_certificate", doc_type: "Experience Certificate", card_field: null },
            { src: "custom_last_salary_slip", doc_type: "Last Salary Slip", card_field: null },
            { src: "resume_attachment", doc_type: "Resume / CV", card_field: null },
            { src: "custom_relieving_letter", doc_type: "Relieving Letter", card_field: null },
            { src: "custom_appointment_offer_letter", doc_type: "Appointment/Offer Letter", card_field: null }
        ];

        frappe.db.get_doc("Job Applicant", frm.doc.job_applicant).then(applicant_doc => {

            let filled = [];

            for (let src in field_mapping) {
                let target = field_mapping[src];
                let value = applicant_doc[src];

                if (value !== undefined && value !== null && value !== "") {

                    // Apply value translation if defined for this target field
                    if (value_mapping[target] && value_mapping[target][value] !== undefined) {
                        value = value_mapping[target][value];
                    }

                    if (!frm.doc[target]) {
                        frm.set_value(target, value);
                        filled.push(target);
                    }
                }
            }

            let docs_added = 0;
            attachment_mapping.forEach(map => {
                let file_url = applicant_doc[map.src];
                if (file_url) {
                    let exists = (frm.doc.employee_documents || []).some(
                        row => row.document_type === map.doc_type
                    );

                    if (!exists) {
                        let row = frm.add_child("employee_documents");
                        row.document_type = map.doc_type;
                        row.file = file_url;
                        if (map.card_field && applicant_doc[map.card_field]) {
                            row.card_number = applicant_doc[map.card_field];
                        }
                        docs_added++;
                    }
                }
            });

            if (docs_added > 0) {
                frm.refresh_field("employee_documents");
            }

            frappe.show_alert({
                message: "Auto-filled " + filled.length + " fields and " + docs_added + " documents from Job Applicant",
                indicator: "green"
            });
        });
    }
});

frappe.ui.form.on('Interview', {
    onload: function(frm) {
        // Auto-set a default interview type silently
        if (!frm.doc.interview_type) {
            frappe.db.get_list('Interview Type', {
                limit: 1
            }).then(function(data) {
                if (data && data.length > 0) {
                    frm.set_value('interview_type', data[0].name);
                }
            });
        }
        // Hide the field
        frm.set_df_property('interview_type', 'hidden', 1);
    }
});

frappe.ui.form.on('Attendance Reason Allocation', {
    refresh(frm) {
        toggle_fields(frm);
    },
    applies_to(frm) {
        frm.set_value('employee', '');
        frm.set_value('employee_name', '');
        frm.set_value('department', '');
        toggle_fields(frm);
    }
});

function toggle_fields(frm) {
    let is_employee   = frm.doc.applies_to === 'Employee';
    let is_department = frm.doc.applies_to === 'Department';

    frm.set_df_property('employee',      'hidden', is_employee   ? 0 : 1);
    frm.set_df_property('employee_name', 'hidden', is_employee   ? 0 : 1);
    frm.set_df_property('department',    'hidden', is_department ? 0 : 1);

    frm.fields_dict['employee']      && frm.fields_dict['employee'].refresh();
    frm.fields_dict['employee_name'] && frm.fields_dict['employee_name'].refresh();
    frm.fields_dict['department']    && frm.fields_dict['department'].refresh();
}

frappe.ui.form.on("Job Offer", {
    job_applicant: function(frm) {
        if (!frm.doc.job_applicant) {
            console.warn("job_applicant is empty, skipping fetch.");
            return;
        }

        frappe.db.get_value("Job Applicant", frm.doc.job_applicant, 
            ["custom_expected_ctc", "custom_current_ctc", "custom_current_employer", 
             "custom_current_designation", "custom_notice_period", 
             "custom_current_location", "custom_preferred_location"],
            function(data) {
                if (!data) return;

                console.log("Fetched data:", data);

                // ✅ FIX: custom_expected_ctc is stored as "1cr", "10L" etc.
                // Show the raw value directly — don't force parseFloat
                if (data.custom_expected_ctc !== null && 
                    data.custom_expected_ctc !== undefined &&
                    data.custom_expected_ctc !== "") {

                    // Since custom_proposed_ctc is Currency type,
                    // we need a clean number — strip all non-numeric chars
                    let raw = String(data.custom_expected_ctc).trim();
                    let numeric = parseFloat(raw.replace(/[^0-9.]/g, ""));

                    if (!isNaN(numeric)) {
                        frm.set_value("custom_proposed_ctc", numeric);
                        frm.refresh_field("custom_proposed_ctc");
                        console.log("Set proposed CTC to:", numeric);
                    } else {
                        // Value like "1cr" can't be auto-converted — show warning
                        frappe.show_alert({
                            message: `Expected CTC is "${raw}" — please enter manually`,
                            indicator: "orange"
                        }, 5);
                        console.warn("Cannot auto-convert CTC value:", raw);
                    }
                }
            }
        );
    }
});

frappe.ui.form.on('Job Requisition', {
    onload: function(frm) {
        if (frm.is_new()) {
            frm.set_value('custom_login_user', frappe.session.user);
        }
    }
});

frappe.ui.form.on('Job Opening', {
    custom_requisition_reference: function(frm) {

        if (!frm.doc.custom_requisition_reference) {
            return;
        }

        frappe.db.get_doc(
            'Job Requisition',
            frm.doc.custom_requisition_reference
        ).then(doc => {

            // Basic Details
            frm.set_value('job_title', doc.designation || '');
            frm.set_value('designation', doc.designation || '');

            // Company Details
            frm.set_value('company', doc.company || '');
            frm.set_value('department', doc.department || '');

            // Employment Type
            frm.set_value(
                'employment_type',
                doc.custom_employee_type || ''
            );

            // Hiring Location
            frm.set_value(
                'location',
                doc.custom_hiring_location || ''
            );

        });

    }
});

frappe.ui.form.on("Staffing Plan", {
    refresh: function(frm) { recalculate_all(frm); },
    onload: function(frm) { recalculate_all(frm); },
    after_save: function(frm) { recalculate_all(frm); }
});

frappe.ui.form.on("Staffing Plan Detail", {
    vacancies: function(frm, cdt, cdn) { calculate_row(frm, cdt, cdn); },
    estimated_cost_per_position: function(frm, cdt, cdn) { calculate_row(frm, cdt, cdn); },
    staffing_details_remove: function(frm) { calculate_total_budget(frm); }
});

function calculate_row(frm, cdt, cdn) {
    var row = locals[cdt][cdn];
    var v = flt(row.vacancies);
    var c = flt(row.estimated_cost_per_position);
    frappe.model.set_value(cdt, cdn, "total_estimated_cost", v * c);
    setTimeout(function() { calculate_total_budget(frm); }, 300);
}

function calculate_total_budget(frm) {
    var total = 0;
    $.each(frm.doc.staffing_details || [], function(i, d) {
        total += flt(d.total_estimated_cost);
    });
    frm.set_value("total_estimated_budget", total);
    frm.refresh_field("total_estimated_budget");
}

function recalculate_all(frm) {
    $.each(frm.doc.staffing_details || [], function(i, d) {
        d.total_estimated_cost = flt(d.vacancies) * flt(d.estimated_cost_per_position);
    });
    frm.refresh_field("staffing_details");
    calculate_total_budget(frm);
}

