frappe.ui.form.on('Job Applicant', {
    refresh(frm) {
        // Show Send Pre-Offer Form button
        if (!frm.is_new()) {

            if (frm.doc.custom_preoffer_form_sent) {
                // Already sent — show resend button
                frm.add_custom_button(__('Resend Pre-Offer Form'), function() {
                    send_preoffer_form(frm);
                }, __('Pre-Offer')).addClass('btn-warning');

                // Show sent info
                frm.set_intro(
                    __('Pre-Offer Form sent on {0} by {1}',
                    [
                        frappe.datetime.str_to_user(frm.doc.custom_preoffer_sent_on),
                        frm.doc.custom_preoffer_sent_by
                    ]),
                    'green'
                );
            } else {
                // Not sent yet — show send button
                frm.add_custom_button(__('Send Pre-Offer Form'), function() {
                    send_preoffer_form(frm);
                }, __('Pre-Offer')).addClass('btn-primary');
            }
        }
    }
});

function send_preoffer_form(frm) {
    // Confirm before sending
    frappe.confirm(
        __('Send Pre-Offer Form to <b>{0}</b> ({1})?',
        [frm.doc.applicant_name, frm.doc.email_id]),
        function() {
            frappe.call({
                method: 'hrms_custom.api.send_preoffer_form',
                args: {
                    job_applicant: frm.doc.name
                },
                freeze: true,
                freeze_message: __('Sending Pre-Offer Form...'),
                callback: function(r) {
                    if (!r.exc) {
                        frappe.show_alert({
                            message: __('Pre-Offer Form sent to {0}!',
                                [frm.doc.applicant_name]),
                            indicator: 'green'
                        }, 5);
                        frm.reload_doc();
                    }
                }
            });
        }
    );
}

frappe.ui.form.on('Job Offer', {
    refresh(frm) {
        if (!frm.is_new()) {

            // Show offer response status
            if (frm.doc.custom_offer_response === 'Accepted') {
                frm.set_intro('Candidate has ACCEPTED the offer!', 'green');
            } else if (frm.doc.custom_offer_response === 'Rejected') {
                frm.set_intro('Candidate has DECLINED the offer.', 'red');
            } else if (frm.doc.custom_offer_sent) {
                frm.set_intro('Offer Letter sent. Awaiting candidate response...', 'orange');
            }

            if (frm.doc.custom_offer_sent) {
                // Resend button
                frm.add_custom_button(__('Resend Offer Letter'), function() {
                    send_offer_letter(frm);
                }, __('Offer Letter')).addClass('btn-warning');
            } else {
                // Send button
                frm.add_custom_button(__('Send Offer Letter'), function() {
                    send_offer_letter(frm);
                }, __('Offer Letter')).addClass('btn-success');
            }
        }
    }
});

function send_offer_letter(frm) {
    let candidate = frm.doc.applicant_name || frm.doc.job_applicant;
    frappe.confirm(
        __('Send Offer Letter to <b>{0}</b>?<br><br>Candidate will receive an email with Accept/Reject buttons.', [candidate]),
        function() {
            frappe.call({
                method: 'hrms_custom.api.send_offer_letter',
                args: { job_offer: frm.doc.name },
                freeze: true,
                freeze_message: __('Sending Offer Letter...'),
                callback: function(r) {
                    if (!r.exc && r.message && r.message.success) {
                        frappe.show_alert({
                            message: r.message.message,
                            indicator: 'green'
                        }, 7);
                        frm.reload_doc();
                    }
                }
            });
        }
    );
}

frappe.ui.form.on('Job Offer', {
    custom_job_requisition(frm) {
        if (!frm.doc.custom_job_requisition) {
            frm.set_value('custom_proposed_ctc', '');
            return;
        }
        frappe.db.get_value(
            'Job Requisition',
            frm.doc.custom_job_requisition,
            [
                'custom_proposed_salarybudget',
                'designation'
            ]
        ).then(r => {
            if (!r.message) return;
            let data = r.message;

            if (data.custom_proposed_salarybudget) {
                let raw = String(data.custom_proposed_salarybudget).trim();
                let numericMatch = raw.match(/[\d,]+(\.\d+)?/);
                if (numericMatch) {
                    let numeric = parseFloat(numericMatch[0].replace(/,/g, ""));
                    if (!isNaN(numeric)) {
                        frm.set_value('custom_proposed_ctc', numeric);
                        frappe.show_alert({
                            message: __('Proposed CTC fetched successfully'),
                            indicator: 'green'
                        });
                    } else {
                        frappe.show_alert({
                            message: __('Could not parse CTC value "{0}" — please enter manually', [raw]),
                            indicator: 'orange'
                        });
                    }
                } else {
                    frappe.show_alert({
                        message: __('CTC value "{0}" not numeric — please enter manually', [raw]),
                        indicator: 'orange'
                    });
                }
            }

            if (data.designation && !frm.doc.designation) {
                frm.set_value('designation', data.designation);
            }
        });
    }
});

frappe.ui.form.on('Attendance Request', {
    refresh(frm) {
        toggle_permission_fields(frm);
    },
    custom_request_type(frm) {
        toggle_permission_fields(frm);
        frm.set_value('custom_permission_type', '');
        frm.set_value('custom_permission_from_time', '');
        frm.set_value('custom_permission_to_time', '');
        frm.set_value('custom_permission_hours', 0);
        if (frm.doc.custom_request_type === 'Permission Request' && frm.doc.from_date) {
            frm.set_value('to_date', frm.doc.from_date);
        }
    },
    reason(frm) {
        validate_date_not_future(frm, 'from_date');
        validate_date_not_future(frm, 'to_date');
    },
    custom_permission_type(frm) {
        fetch_permission_details(frm);
    },
    employee(frm) {
        fetch_permission_details(frm);
    },
    from_date(frm) {
        if (frm.doc.custom_request_type === 'Permission Request' && frm.doc.from_date) {
            frm.set_value('to_date', frm.doc.from_date);
        }
        validate_date_not_future(frm, 'from_date');
        fetch_permission_details(frm);
    },
    to_date(frm) {
        validate_date_not_future(frm, 'to_date');
    }
});
function toggle_permission_fields(frm) {
    const is_permission = frm.doc.custom_request_type === 'Permission Request';
    frm.toggle_display(['half_day', 'half_day_date'], !is_permission);
    frm.toggle_display([
        'custom_permission_type',
        'custom_permission_from_time',
        'custom_permission_to_time',
        'custom_permission_hours'
    ], is_permission);
    frm.set_df_property('to_date', 'read_only', is_permission ? 1 : 0);
}
function validate_date_not_future(frm, fieldname) {
    if (frm.doc.reason !== 'Regularization' || !frm.doc[fieldname]) {
        return;
    }
    if (frappe.datetime.get_diff(frm.doc[fieldname], frappe.datetime.now_date()) > 0) {
        frappe.show_alert({
            message: __('Regularization requests cannot be created for future dates.'),
            indicator: 'red'
        });
        frm.set_value(fieldname, '');
    }
}
function fetch_permission_details(frm) {
    if (
        frm.doc.custom_request_type !== 'Permission Request' ||
        !frm.doc.employee ||
        !frm.doc.from_date ||
        !frm.doc.custom_permission_type
    ) {
        return;
    }
    frappe.show_progress('Calculating...', 50, 100, 'Fetching shift and checkin data');
    frappe.call({
        method: 'hrms_custom.overrides.attendance_request.get_permission_details',
        args: {
            employee: frm.doc.employee,
            permission_date: frm.doc.from_date,
            permission_type: frm.doc.custom_permission_type
        },
        callback(r) {
            frappe.hide_progress();
            if (!r.message) {
                return;
            }
            const d = r.message;
            frm.set_value('custom_permission_from_time', d.permission_from_time);
            frm.set_value('custom_permission_to_time', d.permission_to_time);
            frm.set_value('custom_permission_hours', d.permission_hours);
            frappe.show_alert({
                message: `${frm.doc.custom_permission_type}: ${d.permission_from_time.substring(0, 5)} to ${d.permission_to_time.substring(0, 5)} (${d.permission_hours} hrs)`,
                indicator: 'blue'
            }, 6);
        },
        error() {
            frappe.hide_progress();
        }
    });
}
